  private _getba7RiskProgress(): number {
    return Math.round(this._ba7RiskAssessmentWorkflow.filter(s => s.status === 'completed').length / this._ba7RiskAssessmentWorkflow.length * 100);
  }

  private _getba7TreatmentSummary(): {total: number; approved: number; avgReduction: number; investment: string} {
    const a = this._ba7TreatmentOptions.filter(r => r.status === 'approved').length;
    const avg = this._ba7TreatmentOptions.reduce((s, r) => s + ((r.before - r.after) / r.before * 100), 0) / this._ba7TreatmentOptions.length;
    return {total: this._ba7TreatmentOptions.length, approved: a, avgReduction: Math.round(avg), investment: '$1.125M annually'};
  }

  private _getba7RuleSummary(): {total: number; passing: number; failing: number; avgRate: number; violations: number} {
    const p = this._ba7ComplianceRules.filter(r => r.result === 'pass').length;
    const f = this._ba7ComplianceRules.filter(r => r.result === 'fail').length;
    const avg = this._ba7ComplianceRules.reduce((s, r) => s + r.passRate, 0) / this._ba7ComplianceRules.length;
    const v = this._ba7ComplianceRules.reduce((s, r) => s + r.violations, 0);
    return {total: this._ba7ComplianceRules.length, passing: p, failing: f, avgRate: Math.round(avg * 10) / 10, violations: v};
  }

  private _getba7PipelineStats(): {positions: number; applicants: number; interviewing: number; offers: number; critical: number} {
    const t = this._ba7TalentPositions.length;
    const a = this._ba7TalentPositions.reduce((s, p) => s + p.applicants, 0);
    const i = this._ba7TalentPositions.reduce((s, p) => s + p.interviews, 0);
    const o = this._ba7TalentPositions.reduce((s, p) => s + p.offers, 0);
    const c = this._ba7TalentPositions.filter(x => x.urgency === 'critical').length;
    return {positions: t, applicants: a, interviewing: i, offers: o, critical: c};
  }

  private _getba7MetricTrends(): {improving: number; stable: number; total: number} {
    const imp = this._ba7MetricsDashboard.filter(m => m.trend === 'improving').length;
    const stb = this._ba7MetricsDashboard.filter(m => m.trend === 'stable').length;
    return {improving: imp, stable: stb, total: this._ba7MetricsDashboard.length};
  }

  private _getba7ArchScore(): {total: number; passed: number; failed: number; partial: number; score: number} {
    const p = this._ba7ArchReview.filter(c => c.status === 'pass').length;
    const f = this._ba7ArchReview.filter(c => c.status === 'fail').length;
    const pa = this._ba7ArchReview.filter(c => c.status === 'partial').length;
    return {total: this._ba7ArchReview.length, passed: p, failed: f, partial: pa, score: Math.round((p / this._ba7ArchReview.length) * 100)};
  }


