    const high = this._xba7SecurityAlerts.filter(a => a.severity === 'high').length;
    const med = this._xba7SecurityAlerts.filter(a => a.severity === 'medium').length;
    const low = this._xba7SecurityAlerts.filter(a => a.severity === 'low').length;
    const open = this._xba7SecurityAlerts.filter(a => a.status === 'investigating' || a.status === 'triaged').length;
    const contained = this._xba7SecurityAlerts.filter(a => a.status === 'contained' || a.status === 'remediated').length;
