  private _assessDataExfiltrationIntegrationHealth(): Record<string, unknown> {
    const active = this._data_exfiltrationIntegrations.filter((i: Record<string, unknown>) => i.status === 'active').length;
    const degraded = this._data_exfiltrationIntegrations.filter((i: Record<string, unknown>) => i.status === 'degraded').length;
    const warning = this._data_exfiltrationIntegrations.filter((i: Record<string, unknown>) => i.status === 'warning').length;
    const avgLatency = this._data_exfiltrationIntegrations.reduce((s: number, i: Record<string, unknown>) => s + Number(i.latency), 0) / this._data_exfiltrationIntegrations.length;
    const avgErrorRate = this._data_exfiltrationIntegrations.reduce((s: number, i: Record<string, unknown>) => s + Number(i.errorRate), 0) / this._data_exfiltrationIntegrations.length;
    return {
      totalIntegrations: this._data_exfiltrationIntegrations.length, active, degraded, warning,
      healthScore: Math.round((active / this._data_exfiltrationIntegrations.length) * 100),
      avgLatencyMs: Math.round(avgLatency), avgErrorRate: Math.round(avgErrorRate * 1000) / 10,
      dataFreshness: '95%', coverage: '92%'
    };
  }

  private _monitorDataExfiltrationIntegrationAlerts(): Array<Record<string, unknown>> {
    return this._data_exfiltrationIntegrations
      .filter((i: Record<string, unknown>) => i.status !== 'active')
      .map((i: Record<string, unknown>) => ({
        integrationId: i.integrationId, integrationName: i.name,
        status: i.status, currentErrorRate: Number(i.errorRate) * 100,
        thresholdErrorRate: 5.0, currentLatency: Number(i.latency),
        thresholdLatency: 1000, lastIncident: '2026-04-23T16:' + String(Math.floor(Math.random() * 60)).padStart(2, '0') + ':00Z',
        autoRemediationAttempted: Math.random() > 0.5,
        manualInterventionRequired: Math.random() > 0.6,
        impactDescription: `Integration degraded affecting ${i.name} data flow`
      }));
  }

  private _buildDataExfiltrationDataFlowMatrix(): Array<Record<string, unknown>> {
    const sources = ['SIEM', 'SOAR', 'EDR', 'IAM', 'CSPM', 'DLP', 'Scanner', 'Threat Intel', 'GRC', 'Tickets'];
    const matrix: Array<Record<string, unknown>> = [];
    for (let i = 0; i < sources.length; i++) {
      for (let j = 0; j < sources.length; j++) {
        if (i !== j && Math.random() > 0.6) {
          matrix.push({
            from: sources[i], to: sources[j], dataType: ['alerts', 'ioc', 'config', 'telemetry', 'policy'][Math.floor(Math.random() * 5)],
            frequency: ['realtime', 'near-realtime', 'batch', 'on-demand'][Math.floor(Math.random() * 4)],
            protocol: ['REST', 'Syslog', 'Webhook', 'STIX', 'gRPC'][Math.floor(Math.random() * 5)],
            encrypted: Math.random() > 0.1, authenticated: Math.random() > 0.05,
            dataClassification: ['internal', 'confidential', 'restricted'][Math.floor(Math.random() * 3)]
          });
        }
      }
    }
    return matrix;
  }

